#include <bits/stdc++.h>
using namespace std;
struct Edge{
    int u,v,w;
}edge[5003];
bool cmp(Edge x,Edge y){
    return x.w>y.w;
}
int n,m,s,t,f[502],a=1e8,b=1;
int father(int x){
    return (f[x]==x?x:f[x]=father(f[x]));
}
void merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy)
        f[fy]=fx;
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
        scanf("%d%d%d",&edge[i].u,&edge[i].v,&edge[i].w);
    sort(edge+1,edge+m+1,cmp);
    scanf("%d%d",&s,&t);
    for(int i=1;i<=m;i++){
        //i枚举最小边
        for(int j=1;j<=n;j++)
            f[j]=j;
        for(int j=i;j;j--){
            //j枚举最大边
            merge(edge[j].u,edge[j].v);
            if(father(s)==father(t)){
                if(1LL*edge[j].w*b<1LL*a*edge[i].w)
                    a=edge[j].w,b=edge[i].w;
                break;
            }
        }
    }
    if(a==1e8)
        printf("IMPOSSIBLE");
    else{
        if(b==__gcd(a,b))
            printf("%d",a/__gcd(a,b));
        else
            printf("%d/%d",a/__gcd(a,b),b/__gcd(a,b));
    }
    return 0;
}
